void adaptive_sort(std::vector<int>& arr) {
    if (arr.size() < 2) return;
    bool sorted = true;
    for (size_t i = 1; i < arr.size(); ++i) {
        if (arr[i] < arr[i - 1]) { sorted = false; break; }
    }
    if (!sorted) quicksort(arr, 0, (int)arr.size() - 1);
}

void quicksort(std::vector<int>& arr, int l, int h) {
    if (h - l < 15) {
        for (int i = l + 1; i <= h; ++i) {
            int k = arr[i], j = i - 1;
            while (j >= l && arr[j] > k) { arr[j + 1] = arr[j]; j--; }
            arr[j + 1] = k;
        }
    } else {
        int p = partition(arr, l, h);
        if (p > 0) quicksort(arr, l, p - 1);
        quicksort(arr, p + 1, h);
    }
}

int partition(std::vector<int>& arr, int l, int h) {
    std::swap(arr[l + (h - l) / 2], arr[h]);
    int p = arr[h], i = l;
    for (int j = l; j < h; ++j) {
        if (arr[j] < p) std::swap(arr[i++], arr[j]);
    }
    std::swap(arr[i], arr[h]);
    return i;
}

